+    local procedure CalcMfgOverhead(var StdCostArray: array[6] of Decimal; var ExpCostArray: array[6] of Decimal; var ActCostArray: array[6] of Decimal)
+    var
+        Item: Record Item;
+        ProdOrderLine: Record "Prod. Order Line";
